head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");

scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 
scwin.loginCoCd = "'"+$c.data.getMemInfo("coCd")+"'";
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.loginCoCd)?'':"'"+ scwin.loginCoCd+"'"; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': "'"+scwin.loginCoClsCd+"'";  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)	
scwin.isSubCompany = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        ed_dcsnDt.focus();
    }, {"delay":50});
    scwin.f_Setting();
};

//-------------------------------------------------------------------------
// function name : f_Setting(
// function desc : 날짜셋팅
//-------------------------------------------------------------------------
scwin.f_Setting = function() {
	ds_electronic.set("dcsnDt", $c.date.getServerDateTime("yyyyMMdd"));
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    try {
        /*
        if (!scwin.f_Validation())
		    return;   
        async 처리문제로 로직위치변경
        */
        let ret = await $c.gus.cfValidate([ed_dcsnDt]);
        if (!ret) {
            return false;
        }

        if (!$c.gus.cfIsAfterDate($c.date.getServerDateTime("yyyyMMdd"), ed_dcsnDt.getValue().trim())) {
            let MSG_CM_ERR_061   =  "%1은(는) %2이어야 합니다."
            await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_061,"지급일자","현재일자보다 이후 "));
            ed_dcsnDt.focus();
		    return false;
        }

        if(await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_009,"전자결제파일생성-우리은행")) ) {
            ds_cont.removeAll();
            sbm_save.action = "/ac.fm.paymgnt.paymgnt.CreateWrbFileCMD.do";
            $c.sbm.execute(sbm_save);
        }    

    } catch (e) {
       console.log("f_Save : " + e);
    }
};

//-------------------------------------------------------------------------
// 저장 콜백
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        if (ds_cont.getRowCount() > 0){
            scwin.f_createFile();
            $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_INF_012,"전자결제파일생성-우리은행"));
        }else{
            $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        }

    } catch (e) {
       console.log("sbm_save_submitdone : " + e);
    }
};


//-------------------------------------------------------------------------
// 파일생성
//-------------------------------------------------------------------------
scwin.f_createFile = function() {
    // 파일제목생성
	let title = "(우리)" + $c.date.getServerDateTime("yyyyMMdd");
    const options = {
        fileName : title +".xlsx" ,//[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "전자결재파일"
    };
    const infoArr = [];
    $c.data.downloadGridViewExcel(gr_file, options, infoArr);
};
